/// BTToggleGroup atom barrel.
library;

export 'toggle_group.types.dart';
export 'toggle_group.widget.dart';

/// BTToggleGroup types — Figma node 2864-12585.
library;

export '../toggle/toggle.types.dart'
    show BTToggleSize, BTToggleVariant;

/// A single item in a [BTToggleGroup].
class BTToggleGroupItem<T> {
  const BTToggleGroupItem({
    required this.value,
    required this.label,
    this.disabled = false,
  });

  /// The value associated with this item — used for selection comparison.
  final T value;

  /// Text shown in the toggle button.
  final String label;

  /// When true, this item is non-interactive regardless of group [disabled].
  final bool disabled;
}

/// Selection mode for [BTToggleGroup].
enum BTToggleGroupType {
  /// At most one item active; clicking the active item deselects it
  /// (value → null).
  single,

  /// Any number of items active; clicking toggles membership in the list.
  multiple,
}

/// BTToggleGroup — selection-state container for BTToggle items.
/// Figma source: node 2864-12585.
///
/// Owns selection state internally. Caller optionally seeds initial state via
/// [initialValue] / [initialValues] and receives changes via [onChanged].
///
/// ## Usage:
/// ```dart
/// // Single selection (default)
/// BTToggleGroup<String>(
///   items: const [
///     BTToggleGroupItem(value: 'opt1', label: 'Option 1'),
///     BTToggleGroupItem(value: 'opt2', label: 'Option 2'),
///   ],
///   onChanged: (v) => setState(() => _selected = v),
/// )
///
/// // Multiple selection
/// BTToggleGroup<String>.multiple(
///   items: const [
///     BTToggleGroupItem(value: 'bold',      label: 'Bold'),
///     BTToggleGroupItem(value: 'italic',    label: 'Italic'),
///     BTToggleGroupItem(value: 'underline', label: 'Underline'),
///   ],
///   onChangedMultiple: (v) => setState(() => _selected = v),
/// )
///
/// // Outline variant, disabled entire group
/// BTToggleGroup<String>(
///   items: const [...],
///   variant: BTToggleVariant.outline,
///   disabled: true,
///   onChanged: (_) {},
/// )
/// ```
library;

import 'package:btech_tokens/btech_tokens.dart';
import '../toggle/toggle.widget.dart';
import 'package:btech_ui/src/components/atoms/toggle_group/toggle_group.types.dart';
import 'package:flutter/material.dart';

/// Selection container that renders a row of [BTToggle] items.
/// See file header for usage examples.
class BTToggleGroup<T> extends StatefulWidget {
  /// Single-selection mode — at most one active item.
  const BTToggleGroup({
    required this.items,
    required this.onChanged,
    this.initialValue,
    this.variant = BTToggleVariant.defaultVariant,
    this.size = BTToggleSize.md,
    this.disabled = false,
    super.key,
  })  : type = BTToggleGroupType.single,
        _initialValues = const [],
        onChangedMultiple = null;

  /// Multiple-selection mode — any number of items active.
  const BTToggleGroup.multiple({
    required this.items,
    required this.onChangedMultiple,
    List<T> initialValues = const [],
    this.variant = BTToggleVariant.defaultVariant,
    this.size = BTToggleSize.md,
    this.disabled = false,
    super.key,
  })  : type = BTToggleGroupType.multiple,
        initialValue = null,
        onChanged = null,
        _initialValues = initialValues;

  /// Toggle options.
  final List<BTToggleGroupItem<T>> items;

  /// Selection mode.
  final BTToggleGroupType type;

  /// Forwarded to all child toggles.
  final BTToggleVariant variant;

  /// Forwarded to all child toggles.
  final BTToggleSize size;

  /// When true, all child toggles are disabled.
  final bool disabled;

  // ── Single mode ────────────────────────────────────────────────────────────
  /// Initial selected value (single mode). null = nothing selected.
  final T? initialValue;

  /// Called when selection changes (single mode).
  final ValueChanged<T?>? onChanged;

  // ── Multiple mode ─────────────────────────────────────────────────────────
  final List<T> _initialValues;

  /// Called when selection changes (multiple mode).
  final ValueChanged<List<T>>? onChangedMultiple;

  @override
  State<BTToggleGroup<T>> createState() => _BTToggleGroupState<T>();
}

class _BTToggleGroupState<T> extends State<BTToggleGroup<T>> {
  late T? _selectedSingle;
  late List<T> _selectedMultiple;

  @override
  void initState() {
    super.initState();
    _selectedSingle = widget.initialValue;
    _selectedMultiple = List<T>.from(widget._initialValues);
  }

  bool _isPressed(BTToggleGroupItem<T> item) {
    if (widget.type == BTToggleGroupType.multiple) {
      return _selectedMultiple.contains(item.value);
    }
    return _selectedSingle == item.value;
  }

  void _handleTap(BTToggleGroupItem<T> item) {
    if (widget.disabled || item.disabled) return;
    setState(() {
      if (widget.type == BTToggleGroupType.multiple) {
        if (_selectedMultiple.contains(item.value)) {
          _selectedMultiple =
              _selectedMultiple.where((v) => v != item.value).toList();
        } else {
          _selectedMultiple = [..._selectedMultiple, item.value];
        }
        widget.onChangedMultiple?.call(_selectedMultiple);
      } else {
        _selectedSingle =
            _selectedSingle == item.value ? null : item.value;
        widget.onChanged?.call(_selectedSingle);
      }
    });
  }

  @override
  Widget build(BuildContext context) {
    final gap =
        widget.size == BTToggleSize.sm ? BTSpacing.xs : BTSpacing.sm;

    return Wrap(
      spacing: gap,
      runSpacing: gap,
      children: widget.items.map((item) {
        return BTToggle(
          key: ValueKey(item.value),
          label: item.label,
          pressed: _isPressed(item),
          variant: widget.variant,
          size: widget.size,
          onChanged: (widget.disabled || item.disabled)
              ? null
              : (_) => _handleTap(item),
        );
      }).toList(),
    );
  }
}
